INSERT IGNORE INTO content_articles (id, category, title, published_date, thumbnail, images, content_html, created_at, updated_at) VALUES ('promo001', 'PROMOTION', 'Chương trình tặng quà nhân dịp mùng 8 tháng 3 !!!', '2025-03-04', 'event woman day.webp', '["event woman day.webp", "event woman day 1.webp"]', '<h1>Chương trình tặng quà nhân dịp mùng 8 tháng 3 !!!</h1><span>Đi xem phim Mùng 8-3 nhận ngay gấu xinh (bật mí mấy bé gấu nè hàng limted của chúng tớ nha)</span><br><span>Hơn 100 phần quà đã được chúng tớ chuẩn bị để gửi đến khán giả thân iu nè !!!</span><br><span>Cách thức thực hiện:</span><br><span>Chương trình áp dụng với những khách hàng đến mua vé xem phim tại Trung tâm Chiếu phim Quốc gia trong ngày 8/3 (khách hàng mua vé trực tiếp tại quầy bán vé/máy bán vé tự động và in vé online tại máy bán vé tự động).</span><br><span>Khách có giao dịch mua vé trị giá từ 180.000VNĐ trở lên. Tặng 1 quà/ 1 lần xếp hàng mua vé</span><br><span>Điều kiện: Khách hàng đã quét mã QR quan tâm trang Zalo oa của Trung tâm Chiếu phim Quốc gia</span><br><span>Thời gian áp dụng: Từ 8h00 sáng 8/3 cho đến khi hết quà. Số lượng vô cùng có hạn nên phải nhanh chân đó các bạn ơi !!!</span><br><span>Mùng 8/3 này qua Trung tâm Chiếu phim Quốc gia có siêu nhiều phim hay – Note lịch book vé và nhận ngay quà tặng vô cùng đáng yêu nha!!!</span>', NOW(), NOW());
INSERT IGNORE INTO content_articles (id, category, title, published_date, thumbnail, images, content_html, created_at, updated_at) VALUES ('promo002', 'PROMOTION', 'GÀ RÁN SIÊU MÊ LY ĐỒNG GIÁ CHỈ 79K CÁC SET GÀ RÁN', '2025-05-15', 'children summer 2025.webp', '["children 1.jpg", "children 2.jpg", "children 3.jpg", "children 4.jpg"]', '<h1>GÀ RÁN SIÊU MÊ LY ĐỒNG GIÁ CHỈ 79K CÁC SET GÀ RÁN</h1><span>🌈 Nào nào ~~ mình cùng nắm tay nhau tới Trung tâm Chiếu phim Quốc gia thôi nào!</span><span>📽️ Một mùa hè đầy sắc màu đang chờ đón các bé với những bộ phim hoạt hình siêu xịn, siêu cưng, dễ thương muốn xỉuuu luôn á!! (≧∀≦) 💫</span><span>👧🧒 Bé nào tới rạp cũng mê tít mắt ~~<br>🛋️ Ghế ngồi thì êm ái như mây,<br>🍿 Bắp rang thơm lừng nóng hổi,<br>📺 Màn hình thì to đùng choáng ngợp,<br>🔊 Âm thanh sống động xịn xò hết nước chấm!</span><span>✨ Trải nghiệm điện ảnh hè này chỉ có thể gọi là:<br>👉 Đỉnh của chóp, mê chữ ê kéo dàiiii luôn đó nhaaa!! (*≧ω≦)</span><span>💬 Ai đi chung giơ tay lên nào ~~<br>Đi một lần là ghiền, nhớ hoài không quên luôn ó! ⸜(｡˃ ᵕ ˂ )⸝♡</span>', NOW(), NOW());
INSERT IGNORE INTO content_articles (id, category, title, published_date, thumbnail, images, content_html, created_at, updated_at) VALUES ('promo003', 'PROMOTION', 'CHƯƠNG TRÌNH PHIM HÈ 2025 🎉', '2025-05-15', 'movie summer 2025.webp', '["movie summer 2025.webp"]', '<h1>CHƯƠNG TRÌNH PHIM HÈ 2025 🎉</h1><span>🎉 HÈ NÀY CÙNG ĐẾN TRUNG TÂM CHIẾU PHIM QUỐC GIA XEM PHIM NHÉ!</span><span>📍 Trung tâm Chiếu phim Quốc gia thân tặng ba mẹ và các bạn nhỏ một chương trình phim hè rực rỡ sắc màu và ngập tràn tiếng cười!</span><span>🍿 3 bộ phim hoạt hình siêu dễ thương - Lồng tiếng - Dành cho cả gia đình:</span><h3>🌊 1. Pororo Thám Hiểm Đại Dương Xanh</h3><span>Chú chim cánh cụt Pororo tinh nghịch cùng nhóm bạn sẽ đưa các bé vào chuyến phiêu lưu kỳ thú dưới lòng đại dương! Cùng khám phá những điều bí ẩn và học thêm thật nhiều kiến thức bổ ích về thế giới biển xanh nhé!</span><h3>🌳 2. Siêu Nhân Nhí Đại Náo Rừng Xanh</h3><span>Một cậu bé mơ làm siêu anh hùng bất ngờ bước vào cuộc giải cứu nghẹt thở để bảo vệ một chú hổ bé bỏng khỏi bọn thợ săn độc ác. Liệu tình bạn và lòng dũng cảm có chiến thắng?</span><h3>☁️ 3. Chuyện Muông Thú: Dạy Bé Cừu Bay</h3><span>Bé cừu Woolina luôn ước mơ được bay như những chú chim - dù ai cũng bảo: "Cừu thì không thể bay được!". Với trái tim kiên cường và những người bạn đáng yêu, liệu Woolina có thực hiện được giấc mơ bay trên bầu trời không nhỉ?</span><h3>🎫 Vé xem phim siêu ưu đãi dành cho cả ba mẹ và các bé:</h3><ul><li>✨ Chỉ 35K/vé từ Thứ 2 đến Thứ 5</li><li>✨ Chỉ 45K/vé vào Thứ 6 - Thứ 7 - Chủ Nhật</li></ul><span>🕤 Suất chiếu đặc biệt: 9h30 sáng mỗi ngày<br>📅 Từ ngày 24/05 đến 30/06/2025</span><h3>📌 Đặt vé dễ ơi là dễ:</h3><ul><li>Website: chieuphimquocgia.com.vn</li><li>App NCC</li><li>Các app ngân hàng: BIDV, Vietinbank, Agribank, MB Bank,...</li><li>Ví điện tử VNPAY</li><li>Hoặc mua trực tiếp tại quầy vé nhé!</li></ul><span>👨‍👩‍👧‍👦 Cả nhà mình cùng đến rạp, cùng cười vui và đắm chìm trong thế giới nhiệm màu của những bộ phim tuyệt vời dành riêng cho mùa hè này nha! 💖</span>', NOW(), NOW());
INSERT IGNORE INTO content_articles (id, category, title, published_date, thumbnail, images, content_html, created_at, updated_at) VALUES ('promo004', 'PROMOTION', 'Cinetour "Lật Mặt 8: Vòng tay nắng" khuấy động Trung tâm Chiếu phim Quốc gia', '2025-04-29', 'lat mat 8.webp', '["lat mat 8.webp", "lat mat 8-1.webp", "lat mat 8-2.webp", "lat mat 8-3.webp"]', '<h1>Cinetour "Lật Mặt 8: Vòng tay nắng" khuấy động Trung tâm Chiếu phim Quốc gia</h1><span>Trong khuôn khổ hành trình Cinetour quảng bá bộ phim "Lật Mặt 8: Vòng tay nắng", đoàn làm phim đã có buổi giao lưu đầy cảm xúc với khán giả tại Trung tâm Chiếu phim Quốc gia (NCC). Sự kiện thu hút đông đảo người hâm mộ, mang đến không khí sôi động, gần gũi ấm áp. Đạo diễn Lý Hải cùng dàn diễn viên đã chia sẻ nhiều câu chuyện hậu trường thú vị, đồng thời lắng nghe những phản hồi và tình cảm từ khán giả.</span>', NOW(), NOW());
INSERT IGNORE INTO content_articles (id, category, title, published_date, thumbnail, images, content_html, created_at, updated_at) VALUES ('promo005', 'PROMOTION', 'Cinetour "Thám Tử Kiên: Kỳ Án Không Đầu" - Giao lưu bùng nổ tại Trung tâm Chiếu phim Quốc gia', '2025-04-29', 'ky an khong dau.webp', '["ky an khong dau.webp"]', '<h1>“Cinetour "Thám Tử Kiên: Kỳ Án Không Đầu” - Giao lưu bùng nổ tại Trung tâm Chiếu phim Quốc gia</h1><span>Buổi cinetour của "Thám Tử Kiên: Kỳ Án Không Đầu" đã mang đến không khí sôi động tại Trung tâm Chiếu phim Quốc gia (NCC). Đạo diễn Victor Vũ và dàn diễn viên đã chia sẻ những câu chuyện hậu trường thú vị, những thách thức khi thực hiện các cảnh quay, cùng niềm đam mê cháy bỏng dành cho điện ảnh.</span><span>Phim đang được chiếu tại NCC.</span>', NOW(), NOW());
INSERT IGNORE INTO content_articles (id, category, title, published_date, thumbnail, images, content_html, created_at, updated_at) VALUES ('promo006', 'PROMOTION', 'THẺ QUYỀN LỰC CHO GEN Z ĐÂY RỒI!!!', '2025-04-24', 'card genz.webp', '["card genz.webp"]', '<h1>THẺ QUYỀN LỰC CHO GEN Z ĐÂY RỒI!!!</h1><span>THẺ QUYỀN LỰC CHO GEN Z ĐÂY RỒI!!!</span><span>ĐĂNG KÝ LÀ XÀI LUÔN - ƯU ĐÃI CỰC XỊN DÀNH CHO U22!</span><h3>U22 ƯU ĐÃI KHỦNG - VÉ 2D CHỈ 55K!</h3><span>Bạn là học sinh/sinh viên ≤ 22 tuổi?</span><span>Vé xem phim chỉ còn 55.000đ, áp dụng T2 - T6, mọi suất chiếu nhé!</span><hr><h3>LÀM SAO ĐỂ CÓ "THẺ QUYỀN LỰC" NÀY?</h3><ol><li>Cầm theo CCCD + thẻ HSSV.</li><li>Đến quầy vé/quầy thông tin tại Trung tâm Chiếu phim Quốc gia.</li><li>Đăng ký là kích hoạt & sử dụng ngay luôn!</li></ol><hr><h3>LƯU Ý QUAN TRỌNG (nhớ đọc nha!):</h3><ul><li>Ưu đãi chỉ áp dụng khi mua vé tại quầy</li><li>1 vé/ngày/người/thẻ</li><li>Không áp dụng cho: ghế đôi, ngày lễ/Tết, suất chiếu sớm</li></ul><hr><span>Nhanh tay đăng ký - chill phim cực đã cùng hội bạn thân!</span><span>Còn chờ gì nữa? Gen Z chất chơi là phải có thẻ U22 ngay hôm nay!!!</span>', NOW(), NOW());
INSERT IGNORE INTO content_articles (id, category, title, published_date, thumbnail, images, content_html, created_at, updated_at) VALUES ('promo007', 'PROMOTION', 'ĐỢT PHIM KỶ NIỆM 50 NĂM GIẢI PHÓNG MIỀN NAM, THỐNG NHẤT ĐẤT NƯỚC (30/4/1975 - 30/4/2025) VÀ CÁC NGÀY LỄ LỚN 1/5, 7/5/2025', '2025-04-24', 'movie vietnam.webp', '["30-4-2025.webp"]', '<h1>ĐỢT PHIM KỶ NIỆM 50 NĂM GIẢI PHÓNG MIỀN NAM, THỐNG NHẤT ĐẤT NƯỚC (30/4/1975 – 30/4/2025) VÀ CÁC NGÀY LỄ LỚN 1/5, 7/5/2025</h1><span>KỶ NIỆM 50 NĂM GIẢI PHÓNG MIỀN NAM, THỐNG NHẤT ĐẤT NƯỚC (30/4/1975 - 30/4/2025) VÀ CÁC NGÀY LỄ LỚN 1/5, 7/5/2025</span><span>TRUNG TÂM CHIẾU PHIM QUỐC GIA trân trọng giới thiệu ĐỢT PHIM KỶ NIỆM diễn ra từ ngày 28/4 đến 4/5/2025, nhằm tôn vinh những mốc son lịch sử của dân tộc và khơi dậy tinh thần yêu nước qua ngôn ngữ điện ảnh.</span><h3>CHƯƠNG TRÌNH GIỚI THIỆU 6 TÁC PHẨM ĐIỆN ẢNH:</h3><h4>Phim tài liệu:</h4><ul><li>Tỉnh thức và hóa giải</li><li>Thống nhất Đất nước- Con đường đã chọn</li><li>Nhà thầu khoán Năm USom</li></ul><h4>Phim truyện:</h4><ul><li>Mùi cỏ cháy - những ký ức thời lửa đạn từ góc nhìn tuổi trẻ.</li><li>Đừng đốt - câu chuyện lay động từ cuốn nhật ký Đặng Thùy Trâm.</li><li>Vầng trăng thơ ấu - tuổi thơ Bác Hồ qua lăng kính nghệ thuật đầy tinh tế.</li></ul><span><strong>GIẤY MỜI ĐƯỢC PHÁT MIỄN PHÍ</strong> tại quầy vé Trung tâm Chiếu phim Quốc gia, bắt đầu từ 8h00 ngày 25/4/2025.</span><span>Kính mời quý khán giả đến sớm để nhận vé và cùng sống lại không khí hào hùng của dân tộc qua những thước phim chân thực, xúc động.</span>', NOW(), NOW());
INSERT IGNORE INTO content_articles (id, category, title, published_date, thumbnail, images, content_html, created_at, updated_at) VALUES ('promo008', 'PROMOTION', 'SUẤT CHIẾU ĐẶC BIỆT SÁNG THỨ 7 TẠI NCC', '2025-04-17', 'movie animation.webp', '["movie animation.webp"]', '<h1>SUẤT CHIẾU ĐẶC BIỆT SÁNG THỨ 7 TẠI NCC</h1><span>SUẤT CHIẾU ĐẶC BIỆT SÁNG THỨ 7 TẠI NCC - LẠC VÀO THẾ GIỚI ĐÁNG YÊU CÙNG "CHUYỆN MUÔNG THÚ DẠY BÉ CỪU BAY"! 💛💛💛</span><span>Hello các "tín đồ màn ảnh"! 🎥</span><span>Bạn đã có hẹn với sáng Thứ Bảy tuần này chưa? Nếu chưa, thì NCC đã sẵn sàng lên lịch cho bạn rồi nè! Mỗi sáng thứ 7 là một trải nghiệm phim ảnh trọn vẹn với những điều bất ngờ siêu dễ thương tại Trung tâm Chiếu phim Quốc gia! 🌈✨</span><h3>🌟 Tuần này có gì hot?</h3><span>🐑 Một câu chuyện ngọt ngào, đầy cảm hứng: CHUYỆN MUÔNG THÚ DẠY BÉ CỪU BAY<br>🕥 Suất chiếu đặc biệt: 10h30 sáng Thứ Bảy, 19/4/2025<br>🎟 Link đặt vé cực nhanh tay: <a href="chieuphimquocgia.com.vn/movies/10709">chieuphimquocgia.com.vn/movies/10709</a></span><span>⚠️ Chỉ 100 vé duy nhất - ai chậm tay là tiếc lắm đó!</span><span>🎁 Và đừng quên! Mỗi khán giả đến xem sẽ được nhận ngay một món quà bí mật siêu xinh - chỉ có ở suất chiếu sáng thứ 7 tại NCC thôi nhé!</span><span>👉 Hãy tag ngay hội bạn thân, người yêu hay dẫn cả nhà cùng đi - để không chỉ xem phim, mà còn gom thêm những kỷ niệm thật đẹp và đáng yêu nha!</span>', NOW(), NOW());
INSERT IGNORE INTO content_articles (id, category, title, published_date, thumbnail, images, content_html, created_at, updated_at) VALUES ('promo009', 'PROMOTION', 'SUẤT CHIẾU ĐẶC BIỆT TẠI TRUNG TÂM CHIẾU PHIM QUỐC GIA!', '2025-03-15', 'movie animation.webp', '["movie animation.webp"]', '<h1>CÁC BẠN ĐÃ BIẾT GÌ VỀ SUẤT CHIẾU ĐẶC BIỆT TẠI TRUNG TÂM CHIẾU PHIM QUỐC GIA MỖI SÁNG THỨ 7 CHƯA NÈ!</h1><span>Với giá vé ưu đãi không đổi, 100% khán giả đặt vé suất chiếu đặc biệt được tặng thêm những phần quà bí mật cực xinh.</span><h3>TUẦN NÀY SUẤT CHIẾU ĐẶC BIỆT TẠI #NCC LÀ BỘ PHIM SÁT THỦ VÔ CÙNG CỰC HÀI ( bản lồng tiếng)</h3><span>Sát Thủ Vô Cùng Cực Hài bản lồng tiếng với sự góp giọng của Năm Thu - Lê Khánh và Thu Diễm - Lê Dương Bảo Lâm hứa hẹn sẽ làm khán giả cười khù....ng, cười không ngậm được miệngggg nhoa!</span><span>Đặt vé xem ngay để không bỏ lỡ nhá</span><ul><li>Thời gian: 15/3/2025</li><li>Suất chiếu: 10h10</li><li>Đặt vé ngay: <a class="http-link" href="https://chieuphimquocgia.com.vn/movies/10660">https://chieuphimquocgia.com.vn/movies/10660</a></li><li>Địa điểm: Trung tâm Chiếu phim Quốc gia</li></ul><span>Số lượng có hạn chỉ 100 vé! Đừng quên chia sẻ sự kiện với người thân, bạn bè và cùng nhau thưởng thức một bộ phim hấp dẫn này nhé!</span>', NOW(), NOW());
INSERT IGNORE INTO content_articles (id, category, title, published_date, thumbnail, images, content_html, created_at, updated_at) VALUES ('promo010', 'PROMOTION', 'Chúc mừng ngày Quốc tế Phụ nữ!!!', '2025-04-17', 'movie animation.webp', '["movie animation.webp"]', '<h1>Chúc mừng ngày Quốc tế Phụ nữ!!!</h1><span>Nhân ngày Quốc tế Phụ nữ 8/3, Trung tâm Chiếu phim Quốc gia (NCC) chúc tất cả các bà/bác/chị/em luôn mạnh khoẻ, xinh đẹp, vui vẻ và hạnh phúc. Chúc 1 nửa thế giới ngày nào cũng đều là ngày 8/3!!!</span><span>Chúc các Quý khán giả thân iu luôn đồng hành cùng NCC chúng mình ...</span>', NOW(), NOW());
INSERT IGNORE INTO content_articles (id, category, title, published_date, thumbnail, images, content_html, created_at, updated_at) VALUES ('news011', 'PROMOTION', 'Chương trình phim hè 2025', '2025-04-17', 'movie animation.webp', '["movie animation.webp"]', '<h1>Chương trình phim hè 2025</h1><span>Chương trình phim hè 2025</span><span>Trung tâm Chiếu phim Quốc gia thân tặng ba mẹ và các bạn nhỏ một chương trình phim hè rực rỡ sắc màu và ngập tràn tiếng cười!</span><span>3 bộ phim hoạt hình siêu dễ thương - Lồng tiếng - Dành cho cả gia đình:</span><h3>1. Pororo Thám Hiểm Đại Dương Xanh</h3><span>Chú chim cánh cụt Pororo tinh nghịch cùng nhóm bạn sẽ đưa các bé vào chuyến phiêu lưu kỳ thú dưới lòng đại dương! Cùng khám phá những điều bí ẩn và học thêm thật nhiều kiến thức bổ ích về thế giới biển xanh nhé!</span><h3>2. Siêu Nhân Nhí Đại Náo Rừng Xanh</h3><span>Một cậu bé mơ làm siêu anh hùng bất ngờ bước vào cuộc giải cứu nghẹt thở để bảo vệ một chú hổ bé bỏng khỏi bọn thợ săn độc ác. Liệu tình bạn và lòng dũng cảm có chiến thắng?</span><h3>3. Chuyện Muông Thú: Dạy Bé Cừu Bay</h3><span>Bé cừu Woolina luôn ước mơ được bay như những chú chim - dù ai cũng bảo: "Cừu thì không thể bay được!". Với trái tim kiên cường và những người bạn đáng yêu, liệu Woolina có thực hiện được giấc mơ bay trên bầu trời không nhỉ?</span>', NOW(), NOW());
INSERT IGNORE INTO content_articles (id, category, title, published_date, thumbnail, images, content_html, created_at, updated_at) VALUES ('promo012', 'PROMOTION', 'Chương trình phim hè 2025', '2025-04-17', 'movie animation.webp', '["movie animation.webp"]', '<h1>Chương trình phim hè 2025</h1><span>Chương trình phim hè 2025</span><span>Trung tâm Chiếu phim Quốc gia thân tặng ba mẹ và các bạn nhỏ một chương trình phim hè rực rỡ sắc màu và ngập tràn tiếng cười!</span><span>3 bộ phim hoạt hình siêu dễ thương - Lồng tiếng - Dành cho cả gia đình:</span><h3>1. Pororo Thám Hiểm Đại Dương Xanh</h3><span>Chú chim cánh cụt Pororo tinh nghịch cùng nhóm bạn sẽ đưa các bé vào chuyến phiêu lưu kỳ thú dưới lòng đại dương! Cùng khám phá những điều bí ẩn và học thêm thật nhiều kiến thức bổ ích về thế giới biển xanh nhé!</span><h3>2. Siêu Nhân Nhí Đại Náo Rừng Xanh</h3><span>Một cậu bé mơ làm siêu anh hùng bất ngờ bước vào cuộc giải cứu nghẹt thở để bảo vệ một chú hổ bé bỏng khỏi bọn thợ săn độc ác. Liệu tình bạn và lòng dũng cảm có chiến thắng?</span><h3>3. Chuyện Muông Thú: Dạy Bé Cừu Bay</h3><span>Bé cừu Woolina luôn ước mơ được bay như những chú chim - dù ai cũng bảo: "Cừu thì không thể bay được!". Với trái tim kiên cường và những người bạn đáng yêu, liệu Woolina có thực hiện được giấc mơ bay trên bầu trời không nhỉ?</span>', NOW(), NOW());
