INSERT IGNORE INTO content_articles (id, category, title, published_date, thumbnail, images, content_html, created_at, updated_at) VALUES ('news001', 'NEWS', 'SUẤT CHIẾU ĐẶC BIỆT SÁNG THỨ 7 - CUTE QUÁ TRỜI QUÁ ĐẤT!!!', '2025-05-16', 'doremon movie 45.jpg', '["doremon movie 45.jpg"]', '<h1>🌈✨ SUẤT CHIẾU ĐẶC BIỆT SÁNG THỨ 7 - CUTE QUÁ TRỜI QUÁ ĐẤT!!! ✨🌈</h1><span>🌈✨ SUẤT CHIẾU ĐẶC BIỆT SÁNG THỨ 7 - CUTE QUÁ TRỜI QUÁ ĐẤT!!! ✨🌈</span><span>🎥 Chỉ có tại Trung tâm Chiếu phim Quốc gia - NCC nha cả nhà ơiii~ 🏃‍♀️🏃‍♂️</span><span>💌 Team "yêu phim - thích quà" đâu rồiii?<br>Mỗi sáng Thứ Bảy, tụi mình lại có một món quà nhỏ xinh yêu ơi là yêu:<br>🎁 "Suất chiếu đặc biệt + Quà bí mật siêu iu" dành riêng cho bạn đó nhaaa~ 😍</span><span>🎨 Tuần này có gì nè?<br>Cùng gặp lại mèo ú Doraemon dễ thương với bộ phim mới toanh:<br>🖼️ PHIM ĐIỆN ẢNH DORAEMON: NOBITA VÀ CUỘC PHIÊU LƯU VÀO THẾ GIỚI TRONG TRANH 💙</span><span>📖 Cả nhóm bạn siêu quậy sẽ bước vào một bức tranh nổi tiếng, kết bạn với cô gái bí ẩn tên Claire 👧, rồi cùng khám phá vương quốc Artoria huyền bí - nơi ẩn giấu viên ngọc Artoria Blue lấp lánh ✨<br>🌪️ Nhưng rồi... một truyền thuyết hủy diệt dần sống dậy! Liệu Doraemon và các bạn có cứu được thế giới không ta? 🤯🌀</span><span>🎞️ Phim: PHIM ĐIỆN ẢNH DORAEMON: NOBITA VÀ CUỘC PHIÊU LƯU VÀO THẾ GIỚI TRONG TRANH - BẢN LỒNG TIẾNG<br>🕙 Thời gian: 10h15 sáng Thứ Bảy, 17/5/2025<br>🎟️ Đặt vé lẹ lẹ tại đây nè:<br>👉 <a href="https://chieuphimquocgia.com.vn/movies/10734">https://chieuphimquocgia.com.vn/movies/10734</a></span><span>⏳ Chỉ 100 vé thuiii - Nhanh tay kẻo hết, bỏ lỡ là tiếc hùi hụi đó nhaa 😭💨</span><span>📸 Đi xem phim nhận quà xinh - rủ thêm "đồng bọn" đi chung càng vui nè!<br>🧡 Cả thế giới màu nhiệm đang chờ bạn ~ Let''s gooo!!! 🚀💫</span>', NOW(), NOW());
INSERT IGNORE INTO content_articles (id, category, title, published_date, thumbnail, images, content_html, created_at, updated_at) VALUES ('news002', 'NEWS', 'Các bé xem phim tập thể tại Trung tâm Chiếu phim Quốc gia!!!', '2025-05-15', 'children summer 2025.webp', '["children 1.jpg", "children 2.jpg", "children 3.jpg", "children 4.jpg"]', '<h1>Các bé xem phim tập thể tại Trung tâm Chiếu phim Quốc gia!!!</h1><span>🌈 Nào nào ~~ mình cùng nắm tay nhau tới Trung tâm Chiếu phim Quốc gia thôi nào!</span><span>📽️ Một mùa hè đầy sắc màu đang chờ đón các bé với những bộ phim hoạt hình siêu xịn, siêu cưng, dễ thương muốn xỉuuu luôn á!! (≧∀≦) 💫</span><span>👧🧒 Bé nào tới rạp cũng mê tít mắt ~~<br>🛋️ Ghế ngồi thì êm ái như mây,<br>🍿 Bắp rang thơm lừng nóng hổi,<br>📺 Màn hình thì to đùng choáng ngợp,<br>🔊 Âm thanh sống động xịn xò hết nước chấm!</span><span>✨ Trải nghiệm điện ảnh hè này chỉ có thể gọi là:<br>👉 Đỉnh của chóp, mê chữ ê kéo dàiiii luôn đó nhaaa!! (*≧ω≦)</span><span>💬 Ai đi chung giơ tay lên nào ~~<br>Đi một lần là ghiền, nhớ hoài không quên luôn ó! ⸜(｡˃ ᵕ ˂ )⸝♡</span>', NOW(), NOW());
INSERT IGNORE INTO content_articles (id, category, title, published_date, thumbnail, images, content_html, created_at, updated_at) VALUES ('news003', 'NEWS', 'CHƯƠNG TRÌNH PHIM HÈ 2025 🎉', '2025-05-15', 'movie summer 2025.webp', '["movie summer 2025.webp"]', '<h1>CHƯƠNG TRÌNH PHIM HÈ 2025 🎉</h1><span>🎉 HÈ NÀY CÙNG ĐẾN TRUNG TÂM CHIẾU PHIM QUỐC GIA XEM PHIM NHÉ!</span><span>📍 Trung tâm Chiếu phim Quốc gia thân tặng ba mẹ và các bạn nhỏ một chương trình phim hè rực rỡ sắc màu và ngập tràn tiếng cười!</span><span>🍿 3 bộ phim hoạt hình siêu dễ thương - Lồng tiếng - Dành cho cả gia đình:</span><h3>🌊 1. Pororo Thám Hiểm Đại Dương Xanh</h3><span>Chú chim cánh cụt Pororo tinh nghịch cùng nhóm bạn sẽ đưa các bé vào chuyến phiêu lưu kỳ thú dưới lòng đại dương! Cùng khám phá những điều bí ẩn và học thêm thật nhiều kiến thức bổ ích về thế giới biển xanh nhé!</span><h3>🌳 2. Siêu Nhân Nhí Đại Náo Rừng Xanh</h3><span>Một cậu bé mơ làm siêu anh hùng bất ngờ bước vào cuộc giải cứu nghẹt thở để bảo vệ một chú hổ bé bỏng khỏi bọn thợ săn độc ác. Liệu tình bạn và lòng dũng cảm có chiến thắng?</span><h3>☁️ 3. Chuyện Muông Thú: Dạy Bé Cừu Bay</h3><span>Bé cừu Woolina luôn ước mơ được bay như những chú chim - dù ai cũng bảo: "Cừu thì không thể bay được!". Với trái tim kiên cường và những người bạn đáng yêu, liệu Woolina có thực hiện được giấc mơ bay trên bầu trời không nhỉ?</span><h3>🎫 Vé xem phim siêu ưu đãi dành cho cả ba mẹ và các bé:</h3><ul><li>✨ Chỉ 35K/vé từ Thứ 2 đến Thứ 5</li><li>✨ Chỉ 45K/vé vào Thứ 6 - Thứ 7 - Chủ Nhật</li></ul><span>🕤 Suất chiếu đặc biệt: 9h30 sáng mỗi ngày<br>📅 Từ ngày 24/05 đến 30/06/2025</span><h3>📌 Đặt vé dễ ơi là dễ:</h3><ul><li>Website: chieuphimquocgia.com.vn</li><li>App NCC</li><li>Các app ngân hàng: BIDV, Vietinbank, Agribank, MB Bank,...</li><li>Ví điện tử VNPAY</li><li>Hoặc mua trực tiếp tại quầy vé nhé!</li></ul><span>👨‍👩‍👧‍👦 Cả nhà mình cùng đến rạp, cùng cười vui và đắm chìm trong thế giới nhiệm màu của những bộ phim tuyệt vời dành riêng cho mùa hè này nha! 💖</span>', NOW(), NOW());
INSERT IGNORE INTO content_articles (id, category, title, published_date, thumbnail, images, content_html, created_at, updated_at) VALUES ('news004', 'NEWS', 'Cinetour "Lật Mặt 8: Vòng tay nắng" khuấy động Trung tâm Chiếu phim Quốc gia', '2025-04-29', 'lat mat 8.webp', '["lat mat 8.webp", "lat mat 8-1.webp", "lat mat 8-2.webp", "lat mat 8-3.webp"]', '<h1>Cinetour "Lật Mặt 8: Vòng tay nắng" khuấy động Trung tâm Chiếu phim Quốc gia</h1><span>Trong khuôn khổ hành trình Cinetour quảng bá bộ phim "Lật Mặt 8: Vòng tay nắng", đoàn làm phim đã có buổi giao lưu đầy cảm xúc với khán giả tại Trung tâm Chiếu phim Quốc gia (NCC). Sự kiện thu hút đông đảo người hâm mộ, mang đến không khí sôi động, gần gũi ấm áp. Đạo diễn Lý Hải cùng dàn diễn viên đã chia sẻ nhiều câu chuyện hậu trường thú vị, đồng thời lắng nghe những phản hồi và tình cảm từ khán giả.</span>', NOW(), NOW());
INSERT IGNORE INTO content_articles (id, category, title, published_date, thumbnail, images, content_html, created_at, updated_at) VALUES ('news005', 'NEWS', 'Cinetour "Thám Tử Kiên: Kỳ Án Không Đầu" - Giao lưu bùng nổ tại Trung tâm Chiếu phim Quốc gia', '2025-04-29', 'ky an khong dau.webp', '["ky an khong dau.webp"]', '<h1>“Cinetour "Thám Tử Kiên: Kỳ Án Không Đầu” - Giao lưu bùng nổ tại Trung tâm Chiếu phim Quốc gia</h1><span>Buổi cinetour của "Thám Tử Kiên: Kỳ Án Không Đầu" đã mang đến không khí sôi động tại Trung tâm Chiếu phim Quốc gia (NCC). Đạo diễn Victor Vũ và dàn diễn viên đã chia sẻ những câu chuyện hậu trường thú vị, những thách thức khi thực hiện các cảnh quay, cùng niềm đam mê cháy bỏng dành cho điện ảnh.</span><span>Phim đang được chiếu tại NCC.</span>', NOW(), NOW());
INSERT IGNORE INTO content_articles (id, category, title, published_date, thumbnail, images, content_html, created_at, updated_at) VALUES ('news006', 'NEWS', 'THẺ QUYỀN LỰC CHO GEN Z ĐÂY RỒI!!!', '2025-04-24', 'card genz.webp', '["card genz.webp"]', '<h1>THẺ QUYỀN LỰC CHO GEN Z ĐÂY RỒI!!!</h1><span>THẺ QUYỀN LỰC CHO GEN Z ĐÂY RỒI!!!</span><span>ĐĂNG KÝ LÀ XÀI LUÔN - ƯU ĐÃI CỰC XỊN DÀNH CHO U22!</span><h3>U22 ƯU ĐÃI KHỦNG - VÉ 2D CHỈ 55K!</h3><span>Bạn là học sinh/sinh viên ≤ 22 tuổi?</span><span>Vé xem phim chỉ còn 55.000đ, áp dụng T2 - T6, mọi suất chiếu nhé!</span><hr><h3>LÀM SAO ĐỂ CÓ "THẺ QUYỀN LỰC" NÀY?</h3><ol><li>Cầm theo CCCD + thẻ HSSV.</li><li>Đến quầy vé/quầy thông tin tại Trung tâm Chiếu phim Quốc gia.</li><li>Đăng ký là kích hoạt & sử dụng ngay luôn!</li></ol><hr><h3>LƯU Ý QUAN TRỌNG (nhớ đọc nha!):</h3><ul><li>Ưu đãi chỉ áp dụng khi mua vé tại quầy</li><li>1 vé/ngày/người/thẻ</li><li>Không áp dụng cho: ghế đôi, ngày lễ/Tết, suất chiếu sớm</li></ul><hr><span>Nhanh tay đăng ký - chill phim cực đã cùng hội bạn thân!</span><span>Còn chờ gì nữa? Gen Z chất chơi là phải có thẻ U22 ngay hôm nay!!!</span>', NOW(), NOW());
INSERT IGNORE INTO content_articles (id, category, title, published_date, thumbnail, images, content_html, created_at, updated_at) VALUES ('news007', 'NEWS', 'ĐỢT PHIM KỶ NIỆM 50 NĂM GIẢI PHÓNG MIỀN NAM, THỐNG NHẤT ĐẤT NƯỚC (30/4/1975 - 30/4/2025) VÀ CÁC NGÀY LỄ LỚN 1/5, 7/5/2025', '2025-04-24', 'movie vietnam.webp', '["30-4-2025.webp"]', '<h1>ĐỢT PHIM KỶ NIỆM 50 NĂM GIẢI PHÓNG MIỀN NAM, THỐNG NHẤT ĐẤT NƯỚC (30/4/1975 – 30/4/2025) VÀ CÁC NGÀY LỄ LỚN 1/5, 7/5/2025</h1><span>KỶ NIỆM 50 NĂM GIẢI PHÓNG MIỀN NAM, THỐNG NHẤT ĐẤT NƯỚC (30/4/1975 - 30/4/2025) VÀ CÁC NGÀY LỄ LỚN 1/5, 7/5/2025</span><span>TRUNG TÂM CHIẾU PHIM QUỐC GIA trân trọng giới thiệu ĐỢT PHIM KỶ NIỆM diễn ra từ ngày 28/4 đến 4/5/2025, nhằm tôn vinh những mốc son lịch sử của dân tộc và khơi dậy tinh thần yêu nước qua ngôn ngữ điện ảnh.</span><h3>CHƯƠNG TRÌNH GIỚI THIỆU 6 TÁC PHẨM ĐIỆN ẢNH:</h3><h4>Phim tài liệu:</h4><ul><li>Tỉnh thức và hóa giải</li><li>Thống nhất Đất nước- Con đường đã chọn</li><li>Nhà thầu khoán Năm USom</li></ul><h4>Phim truyện:</h4><ul><li>Mùi cỏ cháy - những ký ức thời lửa đạn từ góc nhìn tuổi trẻ.</li><li>Đừng đốt - câu chuyện lay động từ cuốn nhật ký Đặng Thùy Trâm.</li><li>Vầng trăng thơ ấu - tuổi thơ Bác Hồ qua lăng kính nghệ thuật đầy tinh tế.</li></ul><span><strong>GIẤY MỜI ĐƯỢC PHÁT MIỄN PHÍ</strong> tại quầy vé Trung tâm Chiếu phim Quốc gia, bắt đầu từ 8h00 ngày 25/4/2025.</span><span>Kính mời quý khán giả đến sớm để nhận vé và cùng sống lại không khí hào hùng của dân tộc qua những thước phim chân thực, xúc động.</span>', NOW(), NOW());
INSERT IGNORE INTO content_articles (id, category, title, published_date, thumbnail, images, content_html, created_at, updated_at) VALUES ('news008', 'NEWS', 'SUẤT CHIẾU ĐẶC BIỆT SÁNG THỨ 7 TẠI NCC', '2025-04-17', 'movie animation.webp', '["movie animation.webp"]', '<h1>SUẤT CHIẾU ĐẶC BIỆT SÁNG THỨ 7 TẠI NCC</h1><span>SUẤT CHIẾU ĐẶC BIỆT SÁNG THỨ 7 TẠI NCC - LẠC VÀO THẾ GIỚI ĐÁNG YÊU CÙNG "CHUYỆN MUÔNG THÚ DẠY BÉ CỪU BAY"! 💛💛💛</span><span>Hello các "tín đồ màn ảnh"! 🎥</span><span>Bạn đã có hẹn với sáng Thứ Bảy tuần này chưa? Nếu chưa, thì NCC đã sẵn sàng lên lịch cho bạn rồi nè! Mỗi sáng thứ 7 là một trải nghiệm phim ảnh trọn vẹn với những điều bất ngờ siêu dễ thương tại Trung tâm Chiếu phim Quốc gia! 🌈✨</span><h3>🌟 Tuần này có gì hot?</h3><span>🐑 Một câu chuyện ngọt ngào, đầy cảm hứng: CHUYỆN MUÔNG THÚ DẠY BÉ CỪU BAY<br>🕥 Suất chiếu đặc biệt: 10h30 sáng Thứ Bảy, 19/4/2025<br>🎟 Link đặt vé cực nhanh tay: <a href="chieuphimquocgia.com.vn/movies/10709">chieuphimquocgia.com.vn/movies/10709</a></span><span>⚠️ Chỉ 100 vé duy nhất - ai chậm tay là tiếc lắm đó!</span><span>🎁 Và đừng quên! Mỗi khán giả đến xem sẽ được nhận ngay một món quà bí mật siêu xinh - chỉ có ở suất chiếu sáng thứ 7 tại NCC thôi nhé!</span><span>👉 Hãy tag ngay hội bạn thân, người yêu hay dẫn cả nhà cùng đi - để không chỉ xem phim, mà còn gom thêm những kỷ niệm thật đẹp và đáng yêu nha!</span>', NOW(), NOW());
INSERT IGNORE INTO content_articles (id, category, title, published_date, thumbnail, images, content_html, created_at, updated_at) VALUES ('news009', 'NEWS', 'SUẤT CHIẾU ĐẶC BIỆT TẠI TRUNG TÂM CHIẾU PHIM QUỐC GIA!', '2025-03-15', 'movie special.webp', '["movie special.webp"]', '<h1>CÁC BẠN ĐÃ BIẾT GÌ VỀ SUẤT CHIẾU ĐẶC BIỆT TẠI TRUNG TÂM CHIẾU PHIM QUỐC GIA MỖI SÁNG THỨ 7 CHƯA NÈ!</h1><span>Với giá vé ưu đãi không đổi, 100% khán giả đặt vé suất chiếu đặc biệt được tặng thêm những phần quà bí mật cực xinh.</span><h3>TUẦN NÀY SUẤT CHIẾU ĐẶC BIỆT TẠI #NCC LÀ BỘ PHIM SÁT THỦ VÔ CÙNG CỰC HÀI ( bản lồng tiếng)</h3><span>Sát Thủ Vô Cùng Cực Hài bản lồng tiếng với sự góp giọng của Năm Thu - Lê Khánh và Thu Diễm - Lê Dương Bảo Lâm hứa hẹn sẽ làm khán giả cười khù....ng, cười không ngậm được miệngggg nhoa!</span><span>Đặt vé xem ngay để không bỏ lỡ nhá</span><ul><li>Thời gian: 15/3/2025</li><li>Suất chiếu: 10h10</li><li>Đặt vé ngay: <a class="http-link" href="https://chieuphimquocgia.com.vn/movies/10660">https://chieuphimquocgia.com.vn/movies/10660</a></li><li>Địa điểm: Trung tâm Chiếu phim Quốc gia</li></ul><span>Số lượng có hạn chỉ 100 vé! Đừng quên chia sẻ sự kiện với người thân, bạn bè và cùng nhau thưởng thức một bộ phim hấp dẫn này nhé!</span>', NOW(), NOW());
INSERT IGNORE INTO content_articles (id, category, title, published_date, thumbnail, images, content_html, created_at, updated_at) VALUES ('news010', 'NEWS', 'Chúc mừng ngày Quốc tế Phụ nữ!!!', '2025-04-17', 'woman day.webp', '["woman day.webp"]', '<h1>Chúc mừng ngày Quốc tế Phụ nữ!!!</h1><span>Nhân ngày Quốc tế Phụ nữ 8/3, Trung tâm Chiếu phim Quốc gia (NCC) chúc tất cả các bà/bác/chị/em luôn mạnh khoẻ, xinh đẹp, vui vẻ và hạnh phúc. Chúc 1 nửa thế giới ngày nào cũng đều là ngày 8/3!!!</span><span>Chúc các Quý khán giả thân iu luôn đồng hành cùng NCC chúng mình ...</span>', NOW(), NOW());
INSERT IGNORE INTO content_articles (id, category, title, published_date, thumbnail, images, content_html, created_at, updated_at) VALUES ('news011', 'NEWS', 'Đi xem phim Mùng 8-3 nhận ngay gấu xinh!!!', '2025-03-04', 'event woman day.webp', '["event woman day.webp"]', '<h1>Đi xem phim Mùng 8-3 nhận ngay gấu xinh!!!</h1><span>Đi xem phim Mùng 8-3 nhận ngay gấu xinh (bật mí mấy bé gấu nè hàng limted của chúng tớ nha)</span><span>Hơn 100 phần quà đã được chúng tớ chuẩn bị để gửi đến khán giả thân iu nè !!!</span><span>Cách thức thực hiện:</h3><ul><li>Chương trình áp dụng với những khách hàng đến mua vé xem phim tại Trung tâm Chiếu phim Quốc gia trong ngày 8/3 (khách hàng mua vé trực tiếp tại quầy bán vé/máy bán vé tự động và in vé online tại máy bán vé tự động).</li><li>Khách có giao dịch mua vé trị giá từ 180.000VNĐ trở lên. Tặng 1 quà/ 1 lần xếp hàng mua vé!</li></ul><h3>Điều kiện:</span><span>Khách hàng đã quét mã QR quan tâm trang Zalo oa của Trung tâm Chiếu phim Quốc gia</span><span>Thời gian áp dụng:</span><span>Từ 8h00 sáng 8/3 cho đến khi hết quà. Số lượng vô cùng có hạn nên phải nhanh chân đó các bạn ơi !!!</span><p class="note">Mùng 8/3 này qua Trung tâm Chiếu phim Quốc gia có siêu nhiều phim hay – Note lịch book vé và nhận ngay quà tặng vô cùng đáng yêu nha!!!</p>', NOW(), NOW());
INSERT IGNORE INTO content_articles (id, category, title, published_date, thumbnail, images, content_html, created_at, updated_at) VALUES ('news012', 'NEWS', 'TƯNG BỪNG ƯU ĐÃI năm 2025 tại Trung tâm Chiếu phim Quốc gia ^^', '2025-04-17', 'event 2025.jpg', '["event 2025.jpg"]', '<h1>TƯNG BỪNG ƯU ĐÃI năm 2025 tại Trung tâm Chiếu phim Quốc gia ^^</h1><span>TƯNG BỪNG ƯU ĐÃI năm 2025 tại Trung tâm Chiếu phim Quốc gia.</span><h3>Thứ 2 - Tuần đầu tiên của tháng</h3><span>Bắp rang siêu rẻ đồng giá 25k/1 bỏng ngọt/caramel/phô mai/mix 2 vị</span><h3>Thứ 2 - Tuần thứ hai của tháng</h3><span>Uống nước tràn ly đồng giá 15k/ 1 nước Pepsi/7up/Mirinda/Lipton</span><h3>Thứ 2 - Tuần thứ ba của tháng</h3><span>Gà rán mê ly đồng giá 79k các set gà rán</span><h3>Thứ 2 - Cuối tháng</h3><span>(Các ngày: 20/1, 24/2, 31/3, 28/4, 26/5, 30/6, 28/7, 25/8, 29/9, 27/10, 24/11, 29/12/2025)</span><span>Xem phim hết ý: đồng giá 50k/ 1 vé 2D mọi loại ghế và suất chiếu</span>', NOW(), NOW());
INSERT IGNORE INTO content_articles (id, category, title, published_date, thumbnail, images, content_html, created_at, updated_at) VALUES ('fest001', 'FESTIVAL', 'Liên hoan phim Châu Âu tại Trung tâm Chiếu phim Quốc gia', '2025-05-16', 'Container.png', '["image 1.png", "image 2.png"]', '<span>Từ 14–27.11.2024, Liên hoan phim Châu Âu (EUFF) bởi Phái đoàn EU tại Việt Nam, hợp tác cùng các Đại sứ quán và viện văn hóa của các Quốc gia Thành viên EU, cùng khách mời đặc biệt Đại sứ quán Ukraine tại Việt Nam sẽ diễn ra tại Trung tâm Chiếu phim Quốc gia, Hà Nội. Khai mạc Liên hoan phim sẽ được tổ chức vào 20h ngày 14/11/2024 (Thứ 5) với bộ phim “The Peasants” (Nông dân).</span><br><span>Liên hoan phim Châu Âu năm nay sẽ trình chiếu 18 bộ phim, là 18 cuộc gặp gỡ với những nhân vật đời thường trong những cảnh huống bất thường. Rong ruổi theo chân họ, khán giả sẽ được đi vào hành trình khám phá sâu thẳm nội tâm, tới những làng quê, các cung điện phong kiến, tới một thành phố mê cung, một thành phố hậu chiến, một thành phố cổ tích, và rất nhiều các khung cảnh khác. Tựa như truyền thống của điện ảnh là tấm gương phóng chiếu đời sống, các bộ phim giúp chúng ta nhìn về chính cuộc đời của mình, mơ tới chân trời khác, hay ngẫm suy về những quyết định lớn.</span><br><ul style="list-style-type: ''- '';"><li><strong>Vé mời MIỄN PHÍ tại Hà Nội sẽ được phát từ ngày 05/11/2024 tại những địa điểm dưới đây:</strong></li><li><strong>- Phái đoàn EU tại Việt Nam – Tầng 24, Tòa Tây (Sảnh Văn phòng), Trung tâm Lotte, 54 Liễu Giai, Ba Đình</strong></li><li><strong>Giờ mở cửa: 09:00–12:30; 13:30–17:00 (thứ Hai–thứ Sáu)</strong></li><li><strong>- Viện Goethe Hà Nội – 56-58-60 Nguyễn Thái Học, Ba Đình</strong></li><li><strong>Giờ mở cửa: 08:30–12:00; 13:00–18:00 (thứ Hai–thứ Sáu)</strong></li></ul><br><span>Mỗi khán giả được nhận bốn vé tự chọn. Khán giả khi tới nhận vé không cần đăng ký trước.</span><br><span>Thông tin về lịch chiếu, nội dung phim xem tại website chính thức:<a> https://www.eeas.europa.eu/euff-vietnam-2024_vi?s=184</a></span><br><span>Đón xem các buổi chiếu diễn ra trong khuôn khổ của LHP tại Hà Nội từ 14-27.11.2024.</span><br>', NOW(), NOW());
INSERT IGNORE INTO content_articles (id, category, title, published_date, thumbnail, images, content_html, created_at, updated_at) VALUES ('fest002', 'FESTIVAL', 'Liên hoan Phim Quốc tế Hà Nội lần thứ VII (HANIFF VII)', '2025-05-16', 'Container (1).png', '["calander movie.jpg", "calander movie 1.jpg", "calander movie 2.jpg"]', '<span>Liên hoan Phim Quốc tế Hà Nội lần thứ VII là sự kiện văn hóa nghệ thuật, tôn vinh các tác phẩm điện ảnh có giá trị nghệ thuật cao, giàu tính nhân văn, có dấu ấn sáng tạo nổi bật, độc đáo của quốc tế và Việt Nam. Đây là hoạt động thiết thực chào mừng các ngày lễ lớn của đất nước trong năm 2024 và kỷ niệm 70 năm ngày Giải phóng Thủ đô (10/10/1954 -10/10/2024).</span><br><span>Liên hoan Phim Quốc tế Hà Nội lần thứ VII (LHP) nhằm phát hiện và vinh danh những tài năng mới của điện ảnh; Giới thiệu các tác phẩm đặc sắc của các nền điện ảnh trên thế giới và kết nối, giao lưu hợp tác để cùng phát triển, tạo cơ hội mở rộng thị trường điện ảnh Việt Nam, hội nhập thị trường điện ảnh quốc tế; Thu hút sự quan tâm của khán giả thủ đô Hà Nội và đại biểu quốc tế, góp phần quảng bá Thủ đô Hà Nội, đất nước Việt Nam tươi đẹp, mến khách, thủ đô Hà Nội có truyền thống văn hóa lâu đời, có bề dày lịch sử ngàn năm văn hiến, thành phố vì hòa bình, thành phố đang phát triển mạnh mẽ được UNESCO bình chọn là thành phố sáng tạo.</span><br><span>Với khẩu hiệu <strong style="color: red;">“Điện ảnh: Sáng tạo - Cất cánh”</strong>, Liên hoan Phim Quốc tế Hà Nội không chỉ dừng lại ở một sân chơi nghệ thuật mà còn là nơi khơi nguồn cảm hứng, đưa mỗi tác phẩm đến gần hơn với khán giả toàn cầu.</span><br><span>Liên hoan phim năm nay hứa hẹn mang đến một loạt các sự kiện hấp dẫn và đa dạng, từ những buổi chiếu phim, triển lãm, đến các tọa đàm chuyên sâu về điện ảnh.</span><br><strong style="color: red;">Quý khách nhận vé miễn phí tại các rạp sau:</strong><br><ul style="list-style-type: ''- '';"><li>Trung tâm Chiếu phim Quốc gia</li><li>CGV Nguyễn Chí Thanh</li><li>BHD Phạm Ngọc Thạch</li></ul><br><strong style="color: red;">Thời gian phát vé:</strong> Từ 10h00 ngày 6/11/2024<br><strong style="color: red;">Địa điểm phát vé:</strong> quầy vé/quầy thông tin<br><strong style="color: red;">Số lượng:</strong> tối đa 04 vé/khán giả (phim tùy chọn)<br><span>', NOW(), NOW());
INSERT IGNORE INTO content_articles (id, category, title, published_date, thumbnail, images, content_html, created_at, updated_at) VALUES ('fest003', 'FESTIVAL', 'LÊN TIẾNG CHO MAI SAU: LIÊN HOAN PHIM TÀI LIỆU VỀ PHÁT TRIỂN BỀN VỮNG (30.10.2024-03.11.2024)', '2024-10-28', 'Container (2).png', '["voices for tomorrow.jpg", "voices for tomorrow 2.jpg"]', '', NOW(), NOW());
INSERT IGNORE INTO content_articles (id, category, title, published_date, thumbnail, images, content_html, created_at, updated_at) VALUES ('fest004', 'FESTIVAL', 'Liên hoan phim Đức KinoFest tại Hà Nội', '2025-10-09', 'Container (3).png', '["kinofest.jpg", "kinofest 2.jpg"]', '<span>Liên hoan phim Đức: KinoFest là Liên hoan phim thường niên của Viện Goethe tại Đông Nam Á dành cho điện ảnh đương đại Đức. Sau thành công của hai mùa liên hoan trước vào năm 2022 và 2023, KinoFest 2024 sẽ chính thức quay trở lại Việt Nam trong tháng 10. Khán giả có thể thưởng thức các tác phẩm tại các rạp chiếu phim và địa điểm công cộng ở: Hà Nội, Huế, TP. Hồ Chí Minh, Bình Dương, Đà Lạt, Kiên Giang, Tiền Giang, Cần Thơ.</span><br><span>Sau quá trình tuyển chọn kỹ lưỡng, các thể loại phim tại Liên hoan phim năm nay trải dài từ phim tâm lý, gia đình, hoạt hình đến phiêu lưu, giật gân, khoa học hay những thước phim tài liệu vừa chân thực vừa kỳ ảo – đầy sáng tạo và kích thích trí tưởng tượng. KinoFest 2024 hứa hẹn mang đến những bộ phim đa dạng về hình thức, phản ánh thực tế nhiều vấn đề xã hội diễn ra tại Đức. Đồng thời, đây cũng là lần đầu tiên liên hoan phim Đức tại Việt Nam hướng tới đối tượng trẻ nhỏ và trẻ vị thành niên đặc biệt là vào những suất chiếu cuối tuần.</span><br><span>Đến với Hà Nội, Liên hoan phim sẽ khai mạc vào lúc 18:30 ngày 10.10.2024 tại Trung tâm chiếu phim Quốc gia (NCC) với tựa phim “Phòng Giáo viên”. Tác phẩm đã nhận được nhiều đề cử và chiến thắng tại các giải thưởng danh giá của Đức, châu Âu và châu Mỹ. Nổi bất nhất phải kể đến đề cử Oscar 2024 cho hạng mục ‘Phim quốc tế xuất sắc nhất’.</span><br><span>Vé LHP Đức Kinofest sẽ được mở bán tại Trung tâm Chiếu phim Quốc gia từ ngày 9/10/2024 với giá: 20.000VNĐ/ 1 vé (cả online và offline)<span><br><span>Đặt vé tại: https://chieuphimquocgia.com.vn</span>', NOW(), NOW());
INSERT IGNORE INTO content_articles (id, category, title, published_date, thumbnail, images, content_html, created_at, updated_at) VALUES ('fest005', 'FESTIVAL', 'Tuần lễ phim Iran tại Trung tâm Chiếu phim Quốc gia (10/1 - 14/1/2024)', '2024-01-08', 'Container (5).png', '["film week.jpg", "film week 2.jpg"]', '<span>Tuần lễ phim Iran tại Việt Nam (11/4 – 15/4/2025) </span><br><span>Từ ngày 11/4 đến 15/4/2025, Tuần lễ phim Iran sẽ diễn ra tại Trung tâm Chiếu phim Quốc gia, Hà Nội nhằm mang đến những bộ phim nổi bật nhất, đại diện điện ảnh của xứ sở Ba Tư trong các năm từ 2023-2025. Khai mạc Tuần lễ phim Iran sẽ được tổ chức vào ngày 11/4/2025 (Thứ 6) với bộ phim “Vòng tay đại thụ”. </span><br><span>Tác phẩm mở màn là "Vòng tay đại thụ" (In the Arm of the Tree) được Iran chọn làm đại diện dự thi giải thưởng Oscar năm 2025, hạng mục phim quốc tế xuất sắc nhất. Ngoài ra các bộ phim còn lại bao gồm Mùi hương, Du hành gia đến từ Ganora, “Kẻ gác đền” Beyro, Tạm biệt cô gái Shiraz đều là những bộ phim đặc sắc trình chiếu trong Tuần lễ phim lần này. </span><br><span>Vé xem phim được phát miễn phí tại Quầy thông tin từ ngày 04/4/2025. Khán giả yêu điện ảnh Iran nhanh chóng đến Quầy thông tin để nhận vé!!! </span>', NOW(), NOW());
INSERT IGNORE INTO content_articles (id, category, title, published_date, thumbnail, images, content_html, created_at, updated_at) VALUES ('fest006', 'FESTIVAL', 'TUẦN LỄ CHIẾU PHIM HOẠT HÌNH MIỄN PHÍ', '2024-11-16', 'movie free.jpg', '["movie free.jpg"]', '<span>TUẦN LỄ CHIẾU PHIM HOẠT HÌNH MIỄN PHÍ</span><br><span>Những suất chiếu đầu tiên của Tuần phim miễn phí trong khuôn khổ Liên hoan Phim Hoạt hình Dòng Khát Vọng (TAF 2024) đã sẵn sàng. Check lịch chiếu tại Trung tâm Chiếu phim Quốc gia (ảnh đính kèm) và nhận vé ngay tại quầy thông tin (đối diện quầy bán vé) trước giờ chiếu khi đã đăng ký thông tin tại: <a>https://taf.sconnect.edu.vn/lhpdongkhatvong</a></span><br><ul style="list-style-type: ''- '';"><li>Cách thức nhận vé: Nhận vé trực tiếp trước giờ chiếu của phim đã chọn</li><li>Địa điểm nhận: Quầy thông tin, Tầng 1 (đối diện quầy vé)</li><li>Thời gian nhận: 18:30 -19:00 (ngày 19,20,21/11/2024)</li></ul><br><span>Hẹn gặp bạn vào buổi chiếu phim của TAF 2024 tại Trung tâm Chiếu phim Quốc gia nha!</p><hr><span>Liên hoan Phim Hoạt hình Dòng Khát Vọng lần thứ I với chủ đề “Dòng chảy hoạt hình Việt Nam” được tổ chức trong tháng kỷ niệm 65 năm phát triển của ngành Hoạt hình Việt Nam. Với sự đồng hành của các cơ quan nhà nước, các đơn vị sự nghiệp; sự phối hợp tổ chức của Học viện Đào tạo Hoạt hình Quốc tế Sconnect (SAMA), Liên minh Sáng tạo Nội dung số Việt Nam (DCCA) và Đại sứ quán Pháp tại Việt Nam và sự ủng hộ của các doanh nghiệp trong lĩnh vực,... Liên hoan phim không chỉ là lời tri ân tới các thế hệ nghệ sĩ hoạt hình - những người thầm lặng phía sau thành công của mỗi tác phẩm, mà còn là cơ hội, là bệ phóng tài năng đưa hoạt hình Việt đến gần hơn với công chúng quốc tế.</span><br><span>Tuần lễ chiếu phim miễn phí bắt đầu từ 19/11 với nhiều bộ phim hoạt hình hấp dẫn đến từ Pháp và Việt Nam, mang đến cho bạn những góc nhìn đa dạng về cuộc sống và trải nghiệm điện ảnh đầy cảm xúc.</span><hr><p>Lịch chiếu sẽ tiếp tục được cập nhật trên fanpage Liên hoan phim.</span><br><span>#lienhoanphim #lienhoanphimhoathinh #dongkhatvong #TAF2024</span>', NOW(), NOW());
