INSERT IGNORE INTO content_articles (id, category, title, published_date, thumbnail, images, content_html, created_at, updated_at) VALUES ('fest010', 'FESTIVAL', 'Chương trình phim “Salon Điện ảnh Đài Loan 2024” từ 08/09 - 14/09/2024', '2024-09-06', 'Container (10).png', '["NCC_address.jpg"]', '<div style="text-align: center;"><span><strong>Địa điểm:</strong> diễn ra tại Trung tâm Chiếu phim Quốc gia</span><br><span><strong>Thời gian:</strong> từ 08/9 – 14/9/2024</span></div><br><span>Chương trình đã trải qua 3 kỳ tổ chức thành công từ năm 2020 cho đến nay, "Salon Điện ảnh Đài Loan" đã trở thành một điểm hẹn văn hóa thường niên không thể bỏ lỡ của những người yêu nghệ thuật điện ảnh. Từ 08/9 – 14/9/2024, Văn phòng Kinh tế và Văn hóa Đài Bắc tại Việt Nam tiếp tục phối hợp cùng Trung tâm Chiếu phim Quốc gia tổ chức Chương trình chiếu phim “Salon Điện ảnh Đài Loan 2024” với bộ phim thấm đẫm hơi thở cuộc sống hiện đại, xoay quanh chủ đề phụ nữ, trẻ em và gia đình đã được đề cử cũng như đạt nhiều giải thưởng của điện ảnh Đài Loan sẽ được giới thiệu trong chương trình lần này.</span><br><span>Đặc biệt là tác phẩm điện ảnh từng thống trị bảng xếp hạng phòng vé của Đài Loan năm vừa qua – "Chuyện tôi và ma quỷ thành người một nhà" – 1 trong 10 tác phẩm có doanh thu cao nhất lịch sử điện ảnh Đài Loan. Phim từng ra rạp ở Việt Nam năm 2023 và nhận được sự yêu mến của các khán giả trẻ. Ngoài ra, khán giả Việt sẽ có cơ hội tái ngộ với diễn viên Hứa Quang Hán – gương mặt đại diện cho thế hệ minh tinh mới của Đài Loan.</span><br><span>Vé mời tới tham dự các buổi chiếu được phát <strong>miễn phí</strong> từ ngày <strong>05/09/2024 tại Trung tâm Chiếu phim Quốc Gia</strong>, Văn phòng Kinh tế và Văn hóa Đài Bắc tại Việt Nam và Trường Cao đẳng Nghệ thuật Hà Nội:</span><br><span>- Phát vé tại Quầy thông tin, Tầng 1 từ 17h00 ngày 05/09/2024.</span><br><span>- Vé được phát miễn phí cho các khán giả đến lấy trực tiếp, mỗi khán giả được nhận tối đa 2 vé/phim và được chọn tối đa 04 phim trong tổng số 05 phim được chiếu.</span><br><div style="text-align: center;"><span><strong>Trung tâm Chiếu phim Quốc gia trân trọng thông báo!</strong></span></div>', NOW(), NOW());
